using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver (resolves any type)
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1️⃣ GetTypeInfo<T>() — returns a strongly-typed JsonTypeInfo<T>
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> => Type: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"  Serialized: {json}");

// 2️⃣ TryGetTypeInfo<T>() — probe without throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? probed))
{
    Console.WriteLine($"TryGetTypeInfo<Person> => resolved: {probed!.Type.Name}");
}

// Now demonstrate the "not available" path using a source-gen context
// that only knows about Person, not about Address.
var restrictedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = PersonOnlyContext.Default
};

bool found = restrictedOptions.TryGetTypeInfo<Address>(out JsonTypeInfo<Address>? addressInfo);
Console.WriteLine($"TryGetTypeInfo<Address> on restricted options => found: {found}, info: {addressInfo?.Type.Name ?? "null"}");

// --- Types -----------------------------------------------------------

public record Person(string Name, int Age);
public record Address(string Street, string City);

[JsonSerializable(typeof(Person))]
public partial class PersonOnlyContext : JsonSerializerContext;

